function useInView(threshold = 0.15) {
  const ref = useRef(null);
  const [inView, setInView] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(
      ([e]) => { if (e.isIntersecting) setInView(true); },
      { threshold }
    );
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);
  return [ref, inView];
}

function AnimBar({ level, color, delay = 0 }) {
  const [ref, inView] = useInView(0.1);
  return (
    <div className="pk-bar-bg" ref={ref}>
      <div className="pk-bar-fill" style={{
        width: inView ? `${level}%` : "0%",
        background: color,
        boxShadow: `0 0 8px ${color}88`,
        transitionDelay: `${delay}ms`,
      }} />
    </div>
  );
}

function SectionHeader({ num, title }) {
  const [ref, inView] = useInView();
  return (
    <div className={`pk-section-header pk-fade-up${inView ? " visible" : ""}`} ref={ref}>
      <span className="pk-section-num">{num}</span>
      <div className="pk-section-line" />
      <h2 className="pk-section-title">{title}</h2>
    </div>
  );
}

